#include<bits/stdc++.h>
using namespace std;
int main(){
	int n,a[101][3],b=0,c=0,d=0,num=0;
	cin>>n;
	for(int i=0;i<n;i++){
		for(int j=0;j<3;j++){
			cin>>a[i][j];
		}
	}for(int i=0;i<n;i++){
			for(int j=0;j<3;j++){
				if(j==0){
					b+=a[i][0];
					num+=a[i][0];
				}else if(j==1){
					c+=a[i][1];
					num+=a[i][1];
				}else if(j==2){
					d+=a[i][2];
					num+=a[i][2];
				}
			}
			
		}cout<<b<<" "<<c<<" "<<d<<" "<<num;
	return 0;
}
